// DSOL lexer — tiny hand-rolled tokenizer. Deterministic, no regex
// with /y sticky flags (Safari-compat). Emits tokens for the parser.
//
// Token shape: { kind, value, line, col }
// Token kinds:
//   'kw'       — keyword (contract, dark, entry, …)
//   'ident'    — user identifier
//   'num'      — unsigned integer literal (BigInt string)
//   'str'      — string literal (already unescaped)
//   'punct'    — punctuation (( ) { } ; , . = == != < > <= >= + - * / % @ [ ])
//   'eof'      — end of stream

const KEYWORDS = new Set([
  'dark', 'contract', 'constructor', 'entry', 'function', 'returns',
  'if', 'else', 'for', 'while', 'return', 'require', 'emit', 'syscall',
  'private', 'public', 'mapping', 'struct', 'event',
  'is', 'modifier',
  'uint64', 'int64', 'uint8', 'bool', 'string', 'bytes', 'stealth', 'address',
  // DSOL v2 — privacy-by-default auth types. `wallet_identity` is a
  // 32-byte spend pubkey backing the cross-subaddress equality model
  // (see ~/.claude/plans/dsol-v2-privacy-by-default.md). The
  // `commitment` keyword for Pedersen-keyed user resources is added
  // alongside the Phase-2 contract rewrites — reserving it now would
  // collide with `commitment` parameter names in the existing v4
  // LpManager / Auction sources.
  'wallet_identity',
  'true', 'false', 'when', 'revealed', 'encrypted',
  'msg', 'block', 'ctx', 'this',
  'let', 'const', 'break', 'continue',
  // Phase-4 ergonomics — sugar over `syscall(EXT_CALL_TAIL_V1, {...})`.
  // Kept as a reserved word (not a context-sensitive token) so a future
  // contract can't shadow it with a local of the same name. See
  // parser.js::parseCallTail and codegen.js::emitExtCallTail for the
  // desugar + lower passes.
  'callTail',
]);

const PUNCT_TWO = new Set(['==', '!=', '<=', '>=', '&&', '||', '+=', '-=', '*=', '/=', '->']);
const PUNCT_ONE = new Set(['(', ')', '{', '}', '[', ']', ';', ',', '.', '=', '<', '>', '+', '-', '*', '/', '%', '@', '!', '&', '|', ':']);

export function tokenize(src) {
  const tokens = [];
  let i = 0, line = 1, col = 1;
  const n = src.length;

  function peek(o = 0) { return i + o < n ? src[i + o] : ''; }
  function advance() {
    const c = src[i++];
    if (c === '\n') { line += 1; col = 1; } else { col += 1; }
    return c;
  }

  while (i < n) {
    const c = peek();

    // Whitespace
    if (c === ' ' || c === '\t' || c === '\r' || c === '\n') { advance(); continue; }

    // Line comment
    if (c === '/' && peek(1) === '/') {
      while (i < n && peek() !== '\n') advance();
      continue;
    }
    // Block comment
    if (c === '/' && peek(1) === '*') {
      advance(); advance();
      while (i < n && !(peek() === '*' && peek(1) === '/')) advance();
      if (i < n) { advance(); advance(); }
      continue;
    }

    // String literal
    if (c === '"' || c === '\'') {
      const quote = c;
      const startLine = line, startCol = col;
      advance();
      let val = '';
      while (i < n && peek() !== quote) {
        if (peek() === '\\') {
          advance();
          const esc = advance();
          if (esc === 'n') val += '\n';
          else if (esc === 't') val += '\t';
          else if (esc === 'r') val += '\r';
          else if (esc === '\\') val += '\\';
          else if (esc === '"') val += '"';
          else if (esc === '\'') val += '\'';
          else val += esc;
        } else {
          val += advance();
        }
      }
      if (i >= n) throw new Error(`Unterminated string at line ${startLine}:${startCol}`);
      advance(); // closing quote
      tokens.push({ kind: 'str', value: val, line: startLine, col: startCol });
      continue;
    }

    // Number literal (decimal only; hex supported if prefixed 0x)
    if (c >= '0' && c <= '9') {
      const startLine = line, startCol = col;
      let s = '';
      if (c === '0' && (peek(1) === 'x' || peek(1) === 'X')) {
        s += advance(); s += advance();
        while (i < n && /[0-9a-fA-F_]/.test(peek())) s += advance();
      } else {
        while (i < n && /[0-9_]/.test(peek())) s += advance();
      }
      tokens.push({ kind: 'num', value: s.replace(/_/g, ''), line: startLine, col: startCol });
      continue;
    }

    // Identifier or keyword
    if ((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || c === '_') {
      const startLine = line, startCol = col;
      let s = '';
      while (i < n && /[A-Za-z0-9_]/.test(peek())) s += advance();
      const kind = KEYWORDS.has(s) ? 'kw' : 'ident';
      tokens.push({ kind, value: s, line: startLine, col: startCol });
      continue;
    }

    // Punctuation
    const two = c + peek(1);
    if (PUNCT_TWO.has(two)) {
      const startLine = line, startCol = col;
      advance(); advance();
      tokens.push({ kind: 'punct', value: two, line: startLine, col: startCol });
      continue;
    }
    if (PUNCT_ONE.has(c)) {
      const startLine = line, startCol = col;
      advance();
      tokens.push({ kind: 'punct', value: c, line: startLine, col: startCol });
      continue;
    }

    throw new Error(`Unexpected character '${c}' at line ${line}:${col}`);
  }

  tokens.push({ kind: 'eof', value: '', line, col });
  return tokens;
}



