//   entrypoint:= attrs 'entry' IDENT '(' params ')' returnType? block
//   event_decl:= 'event' IDENT '(' params ')' ';'
//   type      := 'uint64' | 'int64' | 'bool' | 'string' | 'stealth' | 'bytes'
//              | 'mapping' '(' type '=>' type ')'
