// ../build-1261/dark-contracts/compiler/flatten.js
// ─────────────────────────────────────────────────────────────────

// DSOL Phase-3 AST flattener.
//
// Runs BEFORE typecheck. Produces a "flat" contract AST by:
//
//  1. Linearizing `is A, B, C` multi-parent inheritance Solidity-style
//     (left-to-right). Each parent's state variables, events,
//     modifiers, and entries are inlined into the child. Child
//     declarations override parent declarations of the same name
//     (last-writer-wins). Constructor bodies concatenate: parents run
//     before the child.
//
//  2. Inlining `modifier foo(...) { ...; _; ...}` invocations. For
//     each `entry e(...) onlyOwner, nonReentrant { ... }`, the
//     entry body is wrapped by each modifier's body with the `_;`
//     placeholder expanded to the (next inner wrap or) original entry
//     body. Modifier params are hoisted into the entry's local frame
//     as synthetic let-bindings prefixed `__m_<name>` to avoid
//     collisions with entry-scope locals.
//
// After flattening, the AST looks as if the user wrote a single
// monolithic `dark contract X { ... }` with no `is`, no top-level
// modifiers, and no per-entry modifier invocations. Typecheck +
// codegen can proceed unchanged.
//
// Why flatten at AST level (not at bytecode level)?
//   - Keeps the VM simple (no CALL opcodes inside the child's own
//     bytecode; EXT_CALL_TAIL is reserved for cross-contract calls).
//   - Preserves source-map fidelity — the line/col on every inlined
//     statement stays the parent's real location, which is what the
//     user expects when a modifier-enforced require() reverts.
//   - Makes the privacy analysis in typecheck sound: modifier-wrapped
//     private writes show up in the merged entry body, so `@batch`
//     enforcement runs against the real privacy-relevant statement.


// Linearize the inheritance chain. `ast.parents` is an array of parent
// contract names; `resolveParent(name) -> parsed AST` loads each one.
// We recurse so a parent's own `is X, Y` chain is flattened before it
// merges into the child.
export function flattenContract(ast, resolveParent) {
  const withInheritance = linearizeInheritance(ast, resolveParent);
  return inlineModifiers(withInheritance);
}

function linearizeInheritance(ast, resolveParent) {
  if (!ast.parents || ast.parents.length === 0) {
    // No parents — still run modifier inlining later; return unchanged here.
    return cloneContract(ast);
  }
  // Start with an empty shell so we can merge parents in order.
  const merged = {
    kind: 'contract',
    name: ast.name,
    parents: [], // flattened now; reset so downstream passes don't re-flatten
    statevars: [],
    entries: [],
    events: [],
    modifiers: [],
    ctor: null,
    line: ast.line,
    col: ast.col,
  };

  // Process parents left-to-right. Each parent is itself recursively
  // flattened so multi-level inheritance works (A is B is C).
  for (const parentName of ast.parents) {
    const parentAst = resolveParent(parentName);
    if (!parentAst) throw new Error(`parent contract '${parentName}' not found`);
    const parentFlat = linearizeInheritance(parentAst, resolveParent);
    mergeFrom(merged, parentFlat);
  }

  // Apply child declarations last. Last-writer-wins for name clashes.
  mergeFrom(merged, ast);

  return merged;
}

// Merge `src` into `dst` in place. For state/events/modifiers/entries,
// a same-name entry in `src` REPLACES the entry in `dst`. Constructor
// bodies + params concatenate in src-after-dst order (parents first,
// child last).
function mergeFrom(dst, src) {
  for (const sv of src.statevars || []) {
    const ex = dst.statevars.findIndex((x) => x.name === sv.name);
    if (ex >= 0) dst.statevars[ex] = sv;
    else dst.statevars.push(sv);
  }
  for (const ev of src.events || []) {
    const ex = dst.events.findIndex((x) => x.name === ev.name);
    if (ex >= 0) dst.events[ex] = ev;
    else dst.events.push(ev);
  }
  for (const m of src.modifiers || []) {
    const ex = dst.modifiers.findIndex((x) => x.name === m.name);
    if (ex >= 0) dst.modifiers[ex] = m;
    else dst.modifiers.push(m);
  }
  for (const e of src.entries || []) {
    const ex = dst.entries.findIndex((x) => x.name === e.name);
    if (ex >= 0) dst.entries[ex] = e;
    else dst.entries.push(e);
  }
  if (src.ctor) {
    if (!dst.ctor) {
      dst.ctor = {
        kind: 'ctor',
        params: [...src.ctor.params],
        body: { kind: 'block', stmts: [...src.ctor.body.stmts] },
        line: src.ctor.line,
        col: src.ctor.col,
      };
    } else {
      // Concatenate params + stmts: dst (existing parents) first, src last.
      // For the top-level merge in linearizeInheritance, dst=merged was
      // empty so it fills from parents; then child merges last and its
      // own params/body append AFTER all parents' — which is what
      // "parent ctor runs before child ctor" means.
      dst.ctor.params = [...dst.ctor.params, ...src.ctor.params];
      dst.ctor.body.stmts = [...dst.ctor.body.stmts, ...src.ctor.body.stmts];
    }
  }
}

// Deep-clone a contract AST so later merges don't mutate the parser's
// output.
function cloneContract(ast) {
  return JSON.parse(JSON.stringify(ast));
}

// ────────────────────── MODIFIER INLINING ──────────────────────

function inlineModifiers(ast) {
  const modsByName = new Map();
  for (const m of ast.modifiers || []) modsByName.set(m.name, m);

  const newEntries = [];
  for (const e of ast.entries) {
    if (!e.modifiers || e.modifiers.length === 0) {
      newEntries.push(e);
      continue;
    }
    const wrapped = applyEntryModifiers(e, modsByName);
    // Strip modifier list; body now contains fully-expanded logic.
    newEntries.push({ ...wrapped, modifiers: [] });
  }

  // Modifier declarations are no longer needed at the contract level;
  // their bodies are now embedded in the entries that invoked them.
  return { ...ast, entries: newEntries, modifiers: [] };
}

function applyEntryModifiers(entry, modsByName) {
  // Wrap innermost → outermost so the leftmost declared modifier is
  // the outer-most frame. Example:
  //   entry foo(x) onlyOwner, nonReentrant { BODY }
  //   → effective order: onlyOwner wraps nonReentrant wraps BODY.
  let innerBody = entry.body;
  for (let i = entry.modifiers.length - 1; i >= 0; i--) {
    const invocation = entry.modifiers[i];
    const def = modsByName.get(invocation.name);
    if (!def) {
      throw new Error(`modifier '${invocation.name}' not declared`);
    }
    if (def.params.length !== invocation.args.length) {
      throw new Error(
        `modifier '${invocation.name}' expects ${def.params.length} args, got ${invocation.args.length}`,
      );
    }
    innerBody = wrapWithModifier(def, invocation.args, innerBody);
  }
  return { ...entry, body: innerBody };
}

// Wrap `innerBody` (a block) with `modDef`'s body, substituting `_;`
// with innerBody and renaming modifier param idents to `__m_<name>` so
// they don't collide with entry-scope locals. Modifier arguments are
// pre-evaluated by prepending `let __m_<param> = <arg>;` statements at
// the top of the wrapped block — this matches Solidity semantics where
// modifier args are evaluated in the caller's scope.
function wrapWithModifier(modDef, invocationArgs, innerBody) {
  const paramNames = new Set(modDef.params.map((p) => p.name));
  const rename = (node) => renameParamRefs(node, paramNames);

  // 1. Clone and rename every ident in the modifier's body that
  //    references a param, so we can safely prefix.
  const renamedBody = renameParamRefs(modDef.body, paramNames);

  // 2. Walk the renamed body, replacing placeholder statements with
  //    innerBody wholesale.
  const substitutedStmts = substitutePlaceholder(renamedBody.stmts, innerBody);

  // 3. Prepend synthetic let-bindings for each modifier param.
  const paramLets = modDef.params.map((p, i) => ({
    kind: 'let',
    name: `__m_${p.name}`,
    ty: p.type,
    init: invocationArgs[i],
    line: p.line,
    col: p.col,
  }));

  return {
    kind: 'block',
    stmts: [...paramLets, ...substitutedStmts],
  };
}

// Walk a modifier body's statement list, substituting every `_;`
// placeholder (parsed as an exprstmt of ident `_`) with `innerBody`.
// Recurses into nested blocks and if/else branches.
function substitutePlaceholder(stmts, innerBody) {
  const out = [];
  for (const s of stmts) {
    if (isPlaceholder(s)) {
      // Splice innerBody's statements directly so we don't introduce
      // an unnecessary extra block scope.
      out.push(...innerBody.stmts);
      continue;
    }
    if (s.kind === 'block') {
      out.push({ ...s, stmts: substitutePlaceholder(s.stmts, innerBody) });
      continue;
    }
    if (s.kind === 'if') {
      out.push({
        ...s,
        cons: { ...s.cons, stmts: substitutePlaceholder(s.cons.stmts, innerBody) },
        alt: s.alt
          ? (s.alt.kind === 'block'
            ? { ...s.alt, stmts: substitutePlaceholder(s.alt.stmts, innerBody) }
            : s.alt)
          : null,
      });
      continue;
    }
    out.push(s);
  }
  return out;
}

function isPlaceholder(s) {
  return (
    s &&
    s.kind === 'exprstmt' &&
    s.expr &&
    s.expr.kind === 'ident' &&
    s.expr.name === '_'
  );
}

// Recursively rewrite `{kind:'ident', name: P}` to `{kind:'ident',
// name: '__m_' + P}` when P is a modifier param. Pure tree-walk; non-
// AST nodes (primitives, arrays) are passed through.
function renameParamRefs(node, paramNames) {
  if (node == null || typeof node !== 'object') return node;
  if (Array.isArray(node)) return node.map((x) => renameParamRefs(x, paramNames));
  if (node.kind === 'ident' && paramNames.has(node.name)) {
    return { ...node, name: `__m_${node.name}` };
  }
  const out = {};
  for (const k of Object.keys(node)) {
    out[k] = renameParamRefs(node[k], paramNames);
  }
  return out;
}

// Default parent resolver: load from stdlib/<Name>.dsol relative to
// the compiler. Callers can pass a custom resolver for testing or
// for user-space parents.

// Browser stub — the real disk-backed resolver lives in the wallet
// build of flatten.js. The IDE always supplies an explicit resolver
// via `opts.stdlibMap`, so this stub never runs.
export function defaultResolveParent(name) {
  throw new Error('DSOL_COMPILER_NO_DISK_RESOLVER:' + name +
    ' — IDE must pass opts.stdlibMap or opts.resolveParent');
}



