      // Every value type currently supported (u64 + bytes-family) is
      // emitted as a quoted JSON string, so the closing quote suffix
      // is uniform — see the close-quote literal at the bottom of the
      // loop.
      const opener = (i === 0 ? '{' : ',') + '"' + f.key + '":"';
      const openerBytes = new TextEncoder().encode(opener);
      b.pushByte(OP.PUSH_BYTES); b.pushU16(openerBytes.length); b.pushBytes(openerBytes);

      // CONCAT onto the accumulator on subsequent iterations. The
      // first iteration's `{"key":"` IS the accumulator base — no
      // prior bytes value on the stack to merge with.
      if (i > 0) b.pushByte(OP.CONCAT);

